                onSubmitEditing={handleAdd}
                returnKeyType="done"
                multiline
              />
              <TouchableOpacity
                onPress={handleAdd}
                disabled={!newEntry.trim()}
                style={[styles.addBtn, { backgroundColor: newEntry.trim() ? colors.primary : colors.muted }]}
              >
                <Feather name="plus" size={18} color="#fff" />
              </TouchableOpacity>
            </View>
          </View>
        </View>
      </View>
    </Modal>
  );
}

